SELECT SUM(charge_value) AS total_charge
FROM charge_metrics
WHERE excluded = 0;

SELECT AVG(yield_value) AS average_yield
FROM yield_metrics
WHERE dataset_id = 1;

SELECT measurement_date, energy, energy_unit
FROM energy_metrics
WHERE measurement_date = '2013-06-01';

SELECT COUNT(*) AS total_views
FROM access_logs
WHERE access_type = 'view';

SELECT AVG(yield_value) AS average_yield, yield_unit
FROM yield_metrics
GROUP BY yield_unit;

SELECT charge_value
FROM charge_metrics
WHERE converted = 0;

SELECT yield_value, yield_unit
FROM yield_metrics
WHERE harvest_date > '2013-06-01';
